{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./agent-run.codex-output.schema.json",
  "title": "Codex CLI agent run structured output",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "agent_role",
    "agent_id",
    "mode",
    "started_at",
    "completed_at",
    "status",
    "scope",
    "canonical_write_policy",
    "execution",
    "inputs",
    "outputs",
    "quality_checks",
    "blocking_issues",
    "next_actions"
  ],
  "properties": {
    "schema_version": {
      "type": "string",
      "const": "1.0.0"
    },
    "record_type": {
      "type": "string",
      "const": "agent_run"
    },
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
    },
    "agent_role": {
      "type": "string",
      "enum": [
        "triage_agent",
        "search_agent",
        "screening_agent",
        "dedupe_linker_agent",
        "extraction_agent",
        "trial_registry_agent",
        "classification_agent",
        "risk_of_bias_agent",
        "synthesis_agent",
        "review_agent",
        "supervisor_agent",
        "self_healing_agent",
        "release_agent"
      ]
    },
    "agent_id": {
      "type": "string"
    },
    "mode": {
      "type": "string",
      "enum": [
        "bootstrap",
        "surveillance",
        "coverage_repair",
        "extraction_refresh",
        "synthesis_refresh",
        "agent_directed"
      ]
    },
    "started_at": {
      "type": "string"
    },
    "completed_at": {
      "type": "string"
    },
    "status": {
      "type": "string",
      "enum": [
        "succeeded",
        "partial",
        "failed",
        "blocked"
      ]
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "question",
        "hallmark_ids",
        "track_ids",
        "intervention_ids"
      ],
      "properties": {
        "question": {
          "type": "string"
        },
        "hallmark_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        },
        "track_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        },
        "intervention_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        }
      }
    },
    "canonical_write_policy": {
      "type": "string",
      "enum": [
        "no_canonical_writes",
        "candidate_change_required"
      ]
    },
    "execution": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "surface",
        "isolation",
        "workspace_path",
        "prompt_file",
        "prompt_template_file",
        "job_file",
        "output_schema_path",
        "output_path",
        "jsonl_log_path",
        "sandbox",
        "approval_policy"
      ],
      "properties": {
        "surface": {
          "type": "string",
          "enum": [
            "interactive_session",
            "codex_exec",
            "codex_cloud",
            "github_action",
            "other"
          ]
        },
        "isolation": {
          "type": "string",
          "enum": [
            "foreground_checkout",
            "git_worktree",
            "codex_managed_worktree",
            "ci_runner",
            "container",
            "other"
          ]
        },
        "workspace_path": {
          "type": "string"
        },
        "prompt_file": {
          "type": "string"
        },
        "prompt_template_file": {
          "type": [
            "string",
            "null"
          ]
        },
        "job_file": {
          "type": [
            "string",
            "null"
          ]
        },
        "output_schema_path": {
          "type": "string"
        },
        "output_path": {
          "type": "string"
        },
        "jsonl_log_path": {
          "type": "string"
        },
        "sandbox": {
          "type": "string",
          "enum": [
            "read-only",
            "workspace-write",
            "danger-full-access",
            "not_applicable"
          ]
        },
        "approval_policy": {
          "type": "string",
          "enum": [
            "never",
            "on-request",
            "untrusted",
            "not_applicable"
          ]
        }
      }
    },
    "inputs": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "input_type",
          "reference",
          "summary"
        ],
        "properties": {
          "input_type": {
            "type": "string",
            "enum": [
              "user_request",
              "plan_item",
              "coverage_gap",
              "candidate_change",
              "source_snapshot",
              "text_snapshot",
              "record",
              "export",
              "other"
            ]
          },
          "reference": {
            "type": "string"
          },
          "summary": {
            "type": "string"
          }
        }
      }
    },
    "outputs": {
      "anyOf": [
        {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "summary",
            "research_session_id",
            "search_log_id",
            "screening_run_id",
            "generated_files",
            "export_paths"
          ],

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./candidate-change.schema.json",
  "title": "Candidate change",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "name",
    "lifecycle_status",
    "submitted_at",
    "scope",
    "proposed_records",
    "required_review_lanes"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "record_type": {
      "const": "candidate_change"
    },
    "id": {
      "$ref": "./common.schema.json#/$defs/candidateChangeRef"
    },
    "name": {
      "type": "string"
    },
    "summary": {
      "type": "string"
    },
    "lifecycle_status": {
      "enum": [
        "draft",
        "submitted",
        "in_review",
        "needs_revision",
        "accepted",
        "rejected",
        "applied"
      ]
    },
    "submitted_at": {
      "$ref": "./common.schema.json#/$defs/dateTime"
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "question"
      ],
      "properties": {
        "question": {
          "type": "string"
        },
        "hallmark_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/hallmarkRef"
          },
          "uniqueItems": true
        },
        "track_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/trackRef"
          },
          "uniqueItems": true
        }
      }
    },
    "proposed_records": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "record_type",
          "record_id",
          "path",
          "change_type",
          "rationale"
        ],
        "properties": {
          "record_type": {
            "type": "string"
          },
          "record_id": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "path": {
            "type": "string"
          },
          "change_type": {
            "enum": [
              "create",
              "release_accept",
              "update",
              "delete"
            ]
          },
          "rationale": {
            "type": "string"
          }
        }
      }
    },
    "required_review_lanes": {
      "type": "array",
      "items": {
        "enum": [
          "source_fidelity",
          "extraction_fidelity",
          "taxonomy_mapping",
          "synthesis_boundary",
          "safety_limitations"
        ]
      },
      "uniqueItems": true
    },
    "evidence_review_ids": {
      "type": "array",
      "items": {
        "$ref": "./common.schema.json#/$defs/evidenceReviewRef"
      },
      "uniqueItems": true
    },
    "promotion": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "target_status",
        "promoted_at",
        "promoted_by_agent",
        "reviewed_review_ids",
        "summary"
      ],
      "properties": {
        "target_status": {
          "enum": [
            "accepted",
            "applied"
          ]
        },
        "promoted_at": {
          "$ref": "./common.schema.json#/$defs/dateTime"
        },
        "promoted_by_agent": {
          "type": "string"
        },
        "reviewed_review_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/evidenceReviewRef"
          },
          "uniqueItems": true
        },
        "reconciliation_decision_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "uniqueItems": true
        },
        "summary": {
          "type": "string"
        }
      }
    }
  }
}

